import React from 'react';
import { Button, StatusBadge } from '@linm-soft-org/linm-web-common-components';
import df from '../../styles/documentForm.module.css';

export interface DocumentFormHeaderProps {
  onBack: () => void;
  title: string;
  status?: string;
  isReadOnly?: boolean;
  saving?: boolean;
  isNew?: boolean;
  saveLabel?: string;
  saveEditLabel?: string;
  onSave?: () => void;
  onDelete?: () => void;
  showDelete?: boolean;
  deleting?: boolean;
  extraActions?: React.ReactNode;
  testIdPrefix?: string;
  onEdit?: () => void;
  showEdit?: boolean;
}

export const DocumentFormHeader: React.FC<DocumentFormHeaderProps> = ({
  onBack,
  title,
  status,
  isReadOnly,
  saving,
  isNew,
  saveLabel = 'Lưu',
  saveEditLabel = 'Lưu thay đổi',
  onSave,
  onDelete,
  showDelete,
  deleting,
  extraActions,
  testIdPrefix,
  onEdit,
  showEdit,
}) => {
  const tid = (suffix: string) => (testIdPrefix ? `${testIdPrefix}-${suffix}` : undefined);
  return (
  <div className={df.stickyTop}>
    <div className={df.pageHeader}>
      <div className={df.titleGroup}>
        <button type="button" className={df.backBtn} onClick={onBack} data-testid={tid('back-btn')}>
          ← Quay lại
        </button>
        <div>
          <div className={df.titleRow}>
            <h1 className={df.title}>{title}</h1>
            {status && !isNew && <StatusBadge status={status} />}
          </div>
          {isReadOnly && (
            <div className={df.readOnlyHint}>🔒 Chỉ xem — không thể chỉnh sửa</div>
          )}
        </div>
      </div>
      <div className={df.headerActions}>
        {extraActions}
        {showEdit && onEdit && (
          <Button variant="secondary" onClick={onEdit} data-testid={tid('edit-btn')}>
            Sửa
          </Button>
        )}
        {!isReadOnly && onSave && (
          <Button variant="primary" onClick={onSave} loading={saving} data-testid={tid('save-btn')}>
            {isNew ? saveLabel : saveEditLabel}
          </Button>
        )}
        {showDelete && onDelete && (
          <Button variant="danger" onClick={onDelete} loading={deleting} data-testid={tid('delete-btn')}>
            Xóa
          </Button>
        )}
      </div>
    </div>
  </div>
  );
};
